onCreate.script:
// Extract skills from the actor
const skills = actor.system.skills;

// Generate skill selection options dynamically
let skillChoices = Object.entries(skills).map(([key, value]) => {
  return `<option value="${key}">${CONFIG.N5EB.skills[key].label}</option>`;
}).join("");

// Create the dialog for skill selection
let dialogContent = `
  <p>Select two skills to gain proficiency:</p>
  <form>
    <div class="form-group">
      <label for="skill1">Skill 1:</label>
      <select id="skill1" name="skill1">${skillChoices}</select>
    </div>
    <div class="form-group">
      <label for="skill2">Skill 2:</label>
      <select id="skill2" name="skill2">${skillChoices}</select>
    </div>
  </form>
`;

new Dialog({
  title: "Habitual Researcher",
  content: dialogContent,
  buttons: {
    select: {
      icon: "<i class='fas fa-check'></i>",
      label: "Select",
      callback: (html) => {
        let skill1 = html.find("[name='skill1']").val();
        let skill2 = html.find("[name='skill2']").val();

        // Ensure the player has selected two different skills
        if (skill1 === skill2) {
          ui.notifications.error("You must select two different skills.");
          return;
        }

        // Add proficiency to the selected skills
        let updates = {};
        updates[`system.skills.${skill1}.value`] = 1;
        updates[`system.skills.${skill2}.value`] = 1;

        actor.update(updates);

        ui.notifications.info(`You have gained proficiency in ${CONFIG.N5EB.skills[skill1].label} and ${CONFIG.N5EB.skills[skill2].label}.`);
      }
    }
  },
  default: "select"
}).render(true);
